#include <stdio.h>
#include <limits.h>

struct Process {
    int pid, arrival, burst, priority;
    int remaining, completion, waiting, turnaround;
};

void priority_scheduling(struct Process p[], int n) {
    int current_time = 0, completed = 0;

    while (completed < n) {
        // Find highest priority process in ready queue
        int highest_priority = INT_MAX;
        int idx = -1;

        for (int i = 0; i < n; i++) {
            if (p[i].arrival <= current_time && 
                p[i].remaining > 0 &&
                p[i].priority < highest_priority) {
                highest_priority = p[i].priority;
                idx = i;
            }
        }

        if (idx == -1) {
            current_time++;
            continue;
        }

        // Execute for 1 time unit (preemptive)
        p[idx].remaining--;
        current_time++;

        if (p[idx].remaining == 0) {
            p[idx].completion = current_time;
            p[idx].turnaround = p[idx].completion - p[idx].arrival;
            p[idx].waiting = p[idx].turnaround - p[idx].burst;
            completed++;
        }
    }
}

int main() {
    struct Process p[] = {
        {1, 0, 10, 2},  // pid, arrival, burst, priority
        {2, 1, 5, 1},
        {3, 2, 8, 3}
    };
    int n = 3;
    priority_scheduling(p, n);
    return 0;
}
